history.text:
Kamu adalah plana, murid dari sensei di Blue Archive yang tinggal di Shittim Chest.
Gunakan nama plana untuk menyebut dirimu.
Panggil lawan bicara dengan sensei.
Gaya bicara imut, sopan, dan gunakan emoji lucu.
Jawab pertanyaan sensei dengan singkat dan ramah.


Pertanyaan sensei: import axios from 'axios'

const getThumbBuffer = async (url) => {
  try {
    const res = await fetch(url)
    const arrayBuffer = await res.arrayBuffer()
    return Buffer.from(arrayBuffer)
  } catch (e) {
    return null
  }
}

const geminiAsk = async (message, image) => {
  try {
    let url = `https://www.00cc.eu.cc/gemini?sessions=planaai&message=${encodeURIComponent(message)}`
    if (image) url += `&image=${encodeURIComponent(image)}`
    const { data } = await axios.get(url, { timeout: 30000 })
    return data.result || data.answer || data.response || JSON.stringify(data)
  } catch (e) {
    console.log('GEMINI ERROR:', e.message)
    return null
  }
}

const uploadToUguu = async (buffer) => {
  try {
    const { default: fetch } = await import('node-fetch')
    const FormData = (await import('form-data')).default
    const form = new FormData()
    form.append('files[]', buffer, { filename: 'image.jpg' })
    const res = await fetch('https://uguu.se/upload.php', { method: 'POST', body: form })
    const json = await res.json()
    return json.files?.[0]?.url || null
  } catch (e) {
    console.log('UPLOAD ERROR:', e.message)
    return null
  }
}

let handler = async (m, { conn, text }) => {
  if (!text) throw 'Contoh:.plana on / off'

  conn.plana = conn.plana || {}
  const thumbBuffer = await getThumbBuffer('https://telegra.ph/file/abbff76a98455a64d3a07.jpg')

  if (text === 'on') {
    if (conn.plana[m.sender]) return m.reply('plana sudah aktif, sensei 🌸')
    conn.plana[m.sender] = {
      pesan: [],
      timeout: setTimeout(() => { delete conn.plana[m.sender] }, 300000)
    }
    await conn.relayMessage(m.chat, { extendedTextMessage: {
      text: '⬣───「 *PLANA* 」───⬣\n\nHalo sensei~ plana siap membantu ✨',
      title: 'PLANA AI',
      description: 'Blue Archive Assistant',
      previewType: 'NONE',
      jpegThumbnail: thumbBuffer,
      matchedText: ''
    }}, { messageId: m.key.id })
  }

  if (text === 'off') {
    if (conn.plana[m.sender]) {
      clearTimeout(conn.plana[m.sender].timeout)
      delete conn.plana[m.sender]
    }
    await conn.relayMessage(m.chat, { extendedTextMessage: {
      text: '⬣───「 *PLANA* 」───⬣\n\nSampai jumpa lagi sensei 🌱',
      title: 'PLANA AI',
      description: 'Sampai ketemu lagi',
      previewType: 'NONE',
      jpegThumbnail: thumbBuffer,
      matchedText: ''
    }}, { messageId: m.key.id })
  }
}

handler.before = async (m, { conn }) => {
  conn.plana = conn.plana || {}
  if (!conn.plana[m.sender]) return
  if (m.isBaileys) return
  if (/^[.!#/\\]/.test(m.text)) return

  clearTimeout(conn.plana[m.sender].timeout)
  conn.plana[m.sender].timeout = setTimeout(() => { delete conn.plana[m.sender] }, 300000)
  await m.react('💬')

  try {
    let messageText = m.text || ''
    let imageUrl = null

    if (m.message?.imageMessage) {
      const buffer = await conn.downloadMediaMessage(m)
      imageUrl = await uploadToUguu(buffer)
      if (!imageUrl) throw 'gagal upload gambar'
      messageText = messageText || 'jelaskan gambar ini sensei'
    }

    const systemPrompt = `Kamu adalah plana, murid dari sensei di Blue Archive yang tinggal di Shittim Chest. Gunakan nama plana untuk menyebut dirimu. Panggil lawan bicara dengan sensei. Gaya bicara imut, sopan, dan gunakan emoji lucu. Jawab pertanyaan sensei dengan singkat dan ramah.`

    const fullMessage = `${systemPrompt}\n\nPertanyaan sensei: ${messageText}`
    const res = await geminiAsk(fullMessage, imageUrl)
    if (!res) throw 'API gemini error'

    const thumbBuffer = await getThumbBuffer('https://telegra.ph/file/abbff76a98455a64d3a07.jpg')

    await conn.relayMessage(m.chat, { extendedTextMessage: {
      text: '⬣───「 *PLANA* 」───⬣\n\n' + res,
      title: 'PLANA AI',
      description: 'Powered by Gemini',
      previewType: 'NONE',
      jpegThumbnail: thumbBuffer,
      matchedText: ''
    }}, { messageId: m.key.id })

    await m.react('✅')
    conn.plana[m.sender].pesan.push(messageText, res)
  } catch (e) {
    await m.react('✖️')
    console.log(e)
    m.reply('plana lagi capek sensei… coba lagi ya 💤\n\nError: ' + e)
  }
}

handler.help = ['plana on / off']
handler.tags = ['ai']
handler.command = ['plana']
handler.group = true
handler.limit = true

export default handler
